image:image:
  records for Google Image Search (social card or speaker photo).
-#}
{%- set seo = bag('seo') -%}
{%- set noindex_paths = seo['noindex_paths'] -%}

  {%- for page in [site.root] if page != this and page.url_path not in noindex_paths recursive %}

    {{ page|url(external=true) }}
    {%- set lastmod = page['pub_date'] or page['created'] %}
    {%- if lastmod %}
    {{ lastmod }}
    {%- endif %}
    {%- if page['social_card_image'] %}

      {{ site.config.PROJECT.url }}{{ page['social_card_image'] }}
      {{ page['title']|striptags|e }}

    {%- endif %}

  {{- loop(page.children|sort(attribute='path')) }}
  {%- endfor %}
